# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import network
import time
from microcoapy import Coap

# Connect to WLAN
sta_if = network.WLAN(network.STA_IF)
sta_if.active(True)
sta_if.connect('your-ssid', 'your-password')
while not sta_if.isconnected():
    time.sleep(1)

# Initialize CoAP server
coap_server = Coap()

sensor_data = {'temp': 25}
actuator_state = {'light': False}

def handle_get_sensor_temp(packet, addr):
    response_data = str(sensor_data['temp']).encode('utf-8')
    coap_server.sendResponse(addr, packet.messageid, response_data, len(response_data), 
                             packet.token, packet.type, 
                             content_format='text/plain')

def handle_put_actuator_light(packet, addr):
    if packet.payload == b'1':
        actuator_state['light'] = True
    elif packet.payload == b'0':
        actuator_state['light'] = False
    response_message = b'Updated'
    coap_server.sendResponse(addr, packet.messageid, response_message, len(response_message), 
                             packet.token, packet.type, 
                             content_format='text/plain')

# Register resource handlers
coap_server.addResourceCallback('/sensors/temp', handle_get_sensor_temp,
                                methods=['GET'])
coap_server.addResourceCallback('/actuators/light', handle_put_actuator_light,
                                methods=['PUT'])

# Start server
coap_server.start()

try:
    while True:
        coap_server.poll(1000)
except KeyboardInterrupt:
    coap_server.stop()
    print("Server stopped")